@pytest.fixture
async def background_worker():
    task = asyncio.create_task(some_long_running_worker())
    yield task
    task.cancel()
    try:
        await task
    except asyncio.CancelledError:
        pass   # expected — cancellation succeeded

@pytest.mark.asyncio
@pytest.mark.timeout(5)           # wall-clock timeout via pytest-timeout
async def test_with_timeout():
    result = await asyncio.wait_for(
        long_running_operation(),
        timeout=2.0,              # asyncio-level timeout in seconds
    )
